import React from "react";

export default function WeatherOverlay({ condition, isDaytime }) {
  const getOverlayGif = () => {
    const weather = condition?.toLowerCase();

    if (!weather) return null;

    if (weather.includes("thunder")) return "overlays/thunderstorm.gif";
    if (weather.includes("snow")) return "overlays/snow.gif";
    if (weather.includes("wind")) return "overlays/Windy-Weather-App.gif";
    if (weather.includes("rain") && !isDaytime) return "overlays/rainNight.gif";
    if (weather.includes("rain")) return "overlays/rain.gif";
    if (weather.includes("cloud") && isDaytime) return "overlays/PCday.gif";
    if (weather.includes("cloud") && !isDaytime) return "overlays/PCnight.gif";
    if (weather.includes("clear") && isDaytime) return "overlays/noon.gif";
    if (weather.includes("clear") && !isDaytime) return "overlays/night.gif";

    return "overlays/PCdawn.gif"; // fallback
  };

  const gifSrc = getOverlayGif();
  if (!gifSrc) return null;

  return (
    <div className="fixed inset-0 -z-10">
      <img
        src={gifSrc}
        alt="Weather Overlay"
        className="w-full h-full object-cover opacity-60 pointer-events-none select-none"
      />
    </div>
  );
}
